    opt_by_name={o['name']:{'name':o['name'],'hue':o.get('hue','Blue'),'lightness':o.get('lightness','Lighter')} for o in existing}
    before=set(opt_by_name)
    for name in valid_names: opt_by_name.setdefault(name, {'name':name,'hue':'Blue','lightness':'Lighter'})
    options=[]; seen=set()
    for o in existing:
